import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"Instalar Fabric en Windows","description":"Una guía paso a paso de cómo instalar Fabric en Windows.","frontmatter":{"title":"Instalar Fabric en Windows","description":"Una guía paso a paso de cómo instalar Fabric en Windows.","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"es_es/players/installing-fabric/windows.md","filePath":"translated/es_es/players/installing-fabric/windows.md","lastUpdated":1773529007000}`);var s={name:`es_es/players/installing-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalar Fabric en Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalar Fabric en Windows”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Descargar el instalador de Fabric <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Descargar el instalador de Fabric”">​</a></h2><p>Descarga la versión <code>.exe</code> del instalador de Fabric del <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">sitio web de Fabric</a>, clicando en <code>Descargar para Windows</code>.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>La versión <code>.exe</code> para Windows no requiere tener Java instalado, ya que utiliza el Java incluido en el Launcher oficial de Minecraft.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Ejecutar el instalador de Fabric <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Ejecutar el instalador de Fabric”">​</a></h2><p>Cierra Minecraft y el Launcher de Minecraft antes de ejecutar el instalador.</p><p>Tras abrir el instalador, deberías ver una pantalla como la siguiente:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Instalador de Fabric con &quot;Instalar&quot; resaltado" loading="lazy"></p><p>Elige la versión de Minecraft que desees y haz clic en <code>Instalar</code>. Asegúrate de que <code>Create Profile</code> esté marcado.</p><h2 id="3-finish-setup" tabindex="-1">3. Finalizar Configuración <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. Finalizar Configuración”">​</a></h2><p>Una vez la instalación finalice, abre el Launcher de Minecraft. A continuación, selecciona el perfil de Fabric del desplegable de versiones y pulsa Jugar.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher de Minecraft con el perfil de Fabric seleccionado" loading="lazy"></p><p>Ahora puedes añadir mods a tu partida. Ver la guía <a href="./../finding-mods">Encontrar Mods Fiables</a> para más información.</p><p>Si tienes algún problema, no dudes en pedir ayuda en el canal <code>#player-support</code> del <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord de Fabric</a>.</p>`,14)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};